  1→//! MCP Server — exposes canonical Praxis tools over the Model Context Protocol.
  2→//!
  3→//! [`PraxisMcpServer`] bridges the canonical [`ToolRegistry`] to the MCP protocol
  4→//! via rmcp's [`ServerHandler`] trait. Any tools registered in the registry are
  5→//! automatically exposed as MCP tools to connected clients.
  6→//!
  7→//! # Usage
  8→//!
  9→//! ```no_run
 10→//! use aios_protocol::tool::ToolRegistry;
 11→//! use praxis_mcp::server::PraxisMcpServer;
 12→//! use rmcp::ServiceExt;
 13→//! use rmcp::transport::io::stdio;
 14→//!
 15→//! # async fn run() -> Result<(), Box<dyn std::error::Error>> {
 16→//! let registry = ToolRegistry::default();
 17→//! let server = PraxisMcpServer::new(registry);
 18→//! server.serve(stdio()).await?.waiting().await?;
 19→//! # Ok(())
 20→//! # }
 21→//! ```
 22→
 23→use crate::convert::{definition_to_mcp_tool, tool_result_to_call_result};
 24→use aios_protocol::tool::{ToolCall, ToolContext, ToolRegistry};
 25→use rmcp::ErrorData as McpError;
 26→use rmcp::handler::server::ServerHandler;
 27→use rmcp::model::{
 28→    CallToolRequestParams, CallToolResult, Implementation, ListToolsResult, PaginatedRequestParams,
 29→    ServerCapabilities, ServerInfo, Tool as McpToolDef,
 30→};
 31→use rmcp::service::{RequestContext, RoleServer};
 32→use serde_json::Value;
 33→use std::future::Future;
 34→use tracing::{info, warn};
 35→
 36→/// MCP server that exposes all tools from a canonical [`ToolRegistry`].
 37→///
 38→/// Implements rmcp's [`ServerHandler`] trait to serve tools over MCP protocol.
 39→/// The server is transport-agnostic — use it with stdio, Streamable HTTP, or
 40→/// any transport that rmcp supports.
 41→pub struct PraxisMcpServer {
 42→    registry: ToolRegistry,
 43→    server_name: String,
 44→    server_version: String,
 45→}
 46→
 47→impl PraxisMcpServer {
 48→    /// Create a new MCP server with the given tool registry.
 49→    pub fn new(registry: ToolRegistry) -> Self {
 50→        Self {
 51→            registry,
 52→            server_name: "praxis".to_string(),
 53→            server_version: env!("CARGO_PKG_VERSION").to_string(),
 54→        }
 55→    }
 56→
 57→    /// Set a custom server name (default: "praxis").
 58→    pub fn with_name(mut self, name: impl Into<String>) -> Self {
 59→        self.server_name = name.into();
 60→        self
 61→    }
 62→
 63→    /// Set a custom server version.
 64→    pub fn with_version(mut self, version: impl Into<String>) -> Self {
 65→        self.server_version = version.into();
 66→        self
 67→    }
 68→
 69→    /// Access the underlying tool registry.
 70→    pub fn registry(&self) -> &ToolRegistry {
 71→        &self.registry
 72→    }
 73→
 74→    /// Build the MCP tool list from the registry.
 75→    pub fn mcp_tools(&self) -> Vec<McpToolDef> {
 76→        self.registry
 77→            .definitions()
 78→            .iter()
 79→            .map(definition_to_mcp_tool)
 80→            .collect()
 81→    }
 82→}
 83→
 84→impl ServerHandler for PraxisMcpServer {
 85→    fn get_info(&self) -> ServerInfo {
 86→        ServerInfo {
 87→            protocol_version: Default::default(),
 88→            capabilities: ServerCapabilities::builder().enable_tools().build(),
 89→            server_info: Implementation {
 90→                name: self.server_name.clone(),
 91→                version: self.server_version.clone(),
 92→                title: Some("Praxis Tool Engine".to_string()),
 93→                description: Some(
 94→                    "Canonical tool execution engine for the Life Agent OS".to_string(),
 95→                ),
 96→                icons: None,
 97→                website_url: None,
 98→            },
 99→            instructions: Some(
100→                "Praxis exposes filesystem, shell, editing, and memory tools. \
101→                 All filesystem operations are sandboxed within the workspace root."
102→                    .to_string(),
103→            ),
104→        }
105→    }
106→
107→    fn list_tools(
108→        &self,
109→        _request: Option<PaginatedRequestParams>,
110→        _context: RequestContext<RoleServer>,
111→    ) -> impl Future<Output = Result<ListToolsResult, McpError>> + Send + '_ {
112→        let tools = self.mcp_tools();
113→        info!(tool_count = tools.len(), "MCP tools/list");
114→        std::future::ready(Ok(ListToolsResult::with_all_items(tools)))
115→    }
116→
117→    fn call_tool(
118→        &self,
119→        request: CallToolRequestParams,
120→        _context: RequestContext<RoleServer>,
121→    ) -> impl Future<Output = Result<CallToolResult, McpError>> + Send + '_ {
122→        let tool_name = request.name.to_string();
123→        let arguments = request.arguments.unwrap_or_default();
124→
125→        let span = tracing::info_span!(
126→            "mcp_server_call_tool",
127→            tool = %tool_name,
128→            mcp.duration_ms = tracing::field::Empty,
129→            mcp.is_error = tracing::field::Empty,
130→        );
131→        let _guard = span.enter();
132→        let start = std::time::Instant::now();
133→
134→        let result = match self.registry.get(&tool_name) {
135→            Some(tool) => {
136→                let call = ToolCall {
137→                    call_id: uuid::Uuid::new_v4().to_string(),
138→                    tool_name: tool_name.clone(),
139→                    input: Value::Object(arguments),
140→                    requested_capabilities: vec![],
141→                };
142→
143→                let ctx = ToolContext {
144→                    run_id: "mcp".to_string(),
145→                    session_id: "mcp-session".to_string(),
146→                    iteration: 0,
147→                };
148→
149→                match tool.execute(&call, &ctx) {
150→                    Ok(result) => {
151→                        let duration_ms = start.elapsed().as_millis() as u64;
152→                        span.record("mcp.duration_ms", duration_ms);
153→                        span.record("mcp.is_error", result.is_error);
154→                        info!(
155→                            tool = %tool_name,
156→                            duration_ms,
157→                            is_error = result.is_error,
158→                            "MCP tool call completed"
159→                        );
160→                        Ok(tool_result_to_call_result(&result))
161→                    }
162→                    Err(e) => {
163→                        let duration_ms = start.elapsed().as_millis() as u64;
164→                        span.record("mcp.duration_ms", duration_ms);
165→                        span.record("mcp.is_error", true);
166→                        warn!(
167→                            tool = %tool_name,
168→                            error = %e,
169→                            duration_ms,
170→                            "MCP tool call failed"
171→                        );
172→                        Ok(CallToolResult::error(vec![rmcp::model::Content::text(
173→                            e.to_string(),
174→                        )]))
175→                    }
176→                }
177→            }
178→            None => {
179→                warn!(tool = %tool_name, "MCP tool not found");
180→                Err(McpError::invalid_params(
181→                    format!("tool not found: {tool_name}"),
182→                    None,
183→                ))
184→            }
185→        };
186→
187→        std::future::ready(result)
188→    }
189→}
