  1→//! Integration tests: real Praxis tools exposed through the MCP server.
  2→//!
  3→//! Tests the full flow: register tools → build MCP server → call_tool/list_tools.
  4→
  5→use aios_protocol::tool::ToolRegistry;
  6→use praxis_core::local_fs::LocalFs;
  7→use praxis_core::sandbox::{LocalCommandRunner, SandboxPolicy};
  8→use praxis_core::workspace::FsPolicy;
  9→use praxis_mcp::server::PraxisMcpServer;
 10→use praxis_tools::edit::EditFileTool;
 11→use praxis_tools::fs::{GlobTool, GrepTool, ListDirTool, ReadFileTool, WriteFileTool};
 12→use praxis_tools::memory::{ReadMemoryTool, WriteMemoryTool};
 13→use praxis_tools::shell::BashTool;
 14→use serde_json::json;
 15→use std::sync::Arc;
 16→use tempfile::TempDir;
 17→
 18→/// Build a PraxisMcpServer with all filesystem and memory tools.
 19→fn server_with_real_tools(workspace: &std::path::Path) -> PraxisMcpServer {
 20→    let policy = FsPolicy::new(workspace);
 21→    let fs = Arc::new(LocalFs::new(policy));
 22→    let memory_dir = workspace.join(".memory");
 23→    std::fs::create_dir_all(&memory_dir).unwrap();
 24→
 25→    let sandbox_policy = SandboxPolicy::new(workspace);
 26→    let runner = LocalCommandRunner::new();
 27→
 28→    let mut registry = ToolRegistry::default();
 29→    registry.register(ReadFileTool::new(fs.clone()));
 30→    registry.register(WriteFileTool::new(fs.clone()));
 31→    registry.register(ListDirTool::new(fs.clone()));
 32→    registry.register(GlobTool::new(fs.clone()));
 33→    registry.register(GrepTool::new(fs.clone()));
 34→    registry.register(EditFileTool::new(fs));
 35→    registry.register(BashTool::new(sandbox_policy, Box::new(runner)));
 36→    registry.register(ReadMemoryTool::new(memory_dir.clone()));
 37→    registry.register(WriteMemoryTool::new(memory_dir));
 38→
 39→    PraxisMcpServer::new(registry)
 40→}
 41→
 42→/// Helper to call a tool on the server synchronously (mimicking MCP call_tool).
 43→///
 44→/// Exercises the same code path as `ServerHandler::call_tool` but without
 45→/// requiring a full transport/peer setup.
 46→fn call_tool(
 47→    server: &PraxisMcpServer,
 48→    tool_name: &str,
 49→    args: serde_json::Value,
 50→) -> rmcp::model::CallToolResult {
 51→    let call = aios_protocol::tool::ToolCall {
 52→        call_id: "test-call".to_string(),
 53→        tool_name: tool_name.to_string(),
 54→        input: args,
 55→        requested_capabilities: vec![],
 56→    };
 57→    let ctx = aios_protocol::tool::ToolContext {
 58→        run_id: "test-run".to_string(),
 59→        session_id: "test-session".to_string(),
 60→        iteration: 0,
 61→    };
 62→
 63→    let registry_tool = server.registry().get(tool_name).unwrap();
 64→    let result = registry_tool.execute(&call, &ctx).unwrap();
 65→    praxis_mcp::convert::tool_result_to_call_result(&result)
 66→}
